#!/usr/bin/env node
/**
 * Druz9 design-tokens generator — reads source.mjs, emits per-app CSS + TS.
 *
 *   node design/tokens/emit.mjs
 *   make tokens                 (same)
 *
 * Outputs (6 files, all marked @generated, committed to git):
 *   frontend/src/styles/_tokens.generated.css
 *   frontend/src/lib/design-tokens.ts
 *   hone/src/renderer/src/styles/_tokens.generated.css
 *   hone/src/renderer/src/lib/design-tokens.ts
 *   cue/src/renderer/styles/_tokens.generated.css
 *   cue/src/renderer/lib/design-tokens.ts
 *
 * Drift check: `make tokens-check` runs this and fails if `git diff` non-empty.
 */

import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

import { tokens } from './source.mjs';

const HERE = dirname(fileURLToPath(import.meta.url));
const REPO = resolve(HERE, '..', '..');
const SHARED_SRC = resolve(REPO, 'design', 'src');

const kebab = (s) => s.replace(/[A-Z]/g, (m) => '-' + m.toLowerCase());

const HEADER_CSS = `/**
 * @generated by design/tokens/emit.mjs — DO NOT EDIT.
 * Edit design/tokens/source.mjs, then run \`make tokens\`.
 *
 * Foundation tokens (motion + focus + density + breakpoints + typography).
 * Palette tokens stay in each app's existing CSS (additive layer).
 */
`;

const HEADER_TS = `/**
 * @generated by design/tokens/emit.mjs — DO NOT EDIT.
 * Edit design/tokens/source.mjs, then run \`make tokens\`.
 */
`;

function densityVars(mode) {
  const d = tokens.density[mode];
  return Object.entries(d)
    .map(([k, v]) => {
      const name = `--${kebab(k)}`;
      const unit = k === 'lineHeightBody' ? '' : 'px';
      return `  ${name}: ${v}${unit};`;
    })
    .join('\n');
}

function buildCss() {
  const motionDurs = Object.entries(tokens.motion.dur)
    .map(([k, v]) => `  --motion-dur-${k}: ${v}ms;`)
    .join('\n');

  const motionEases = Object.entries(tokens.motion.ease)
    .map(([k, v]) => `  --motion-ease-${k}: ${v};`)
    .join('\n');

  const breakpoints = Object.entries(tokens.breakpoints)
    .map(([k, v]) => `  --bp-${k}: ${v}px;`)
    .join('\n');

  const typo = Object.entries(tokens.typography)
    .map(([slot, def]) => {
      return [
        `  --type-${slot}-size: ${def.size}px;`,
        `  --type-${slot}-lh: ${def.lh};`,
        `  --type-${slot}-ls: ${def.ls};`,
        `  --type-${slot}-weight: ${def.weight};`,
      ].join('\n');
    })
    .join('\n');

  return `${HEADER_CSS}
:root {
  /* motion — durations */
${motionDurs}

  /* motion — easing curves */
${motionEases}

  /* focus ring (single composite shadow, applied via .focus-ring) */
  --focus-ring: ${tokens.focusRing};

  /* density defaults — comfortable */
${densityVars('comfortable')}

  /* breakpoints (informational; tailwind has its own config) */
${breakpoints}

  /* typography scale */
${typo}

  /* responsive helpers */
  --auto-fit-min: 240px;
}

[data-density="compact"] {
${densityVars('compact')}
}

[data-density="spacious"] {
${densityVars('spacious')}
}

/* Universal focus-ring class — apply to any focusable element.
   Pairs with --focus-ring composite shadow above. */
.focus-ring:focus-visible {
  outline: none;
  box-shadow: var(--focus-ring);
}

/* Reduced-motion killswitch — applies to every animation/transition.
   Per-component motion is gated by this single rule, not bespoke media queries. */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}
`;
}

function buildTs() {
  const lines = [HEADER_TS];

  lines.push(`export const motion = {`);
  lines.push(`  dur: {`);
  for (const [k, v] of Object.entries(tokens.motion.dur)) {
    lines.push(`    ${k}: ${v},`);
  }
  lines.push(`  },`);
  lines.push(`  ease: {`);
  for (const [k, v] of Object.entries(tokens.motion.ease)) {
    lines.push(`    ${k}: '${v}',`);
  }
  lines.push(`  },`);
  lines.push(`} as const;`);
  lines.push('');

  lines.push(`export const focusRing = '${tokens.focusRing}' as const;`);
  lines.push('');

  lines.push(`export const density = {`);
  for (const [mode, def] of Object.entries(tokens.density)) {
    lines.push(`  ${mode}: {`);
    for (const [k, v] of Object.entries(def)) {
      lines.push(`    ${k}: ${v},`);
    }
    lines.push(`  },`);
  }
  lines.push(`} as const;`);
  lines.push('');

  lines.push(`export const breakpoints = {`);
  for (const [k, v] of Object.entries(tokens.breakpoints)) {
    const key = /^[a-z]/i.test(k) && !/['"]/.test(k) ? k : `'${k}'`;
    lines.push(`  ${key}: ${v},`);
  }
  lines.push(`} as const;`);
  lines.push('');

  lines.push(`export const typography = {`);
  for (const [slot, def] of Object.entries(tokens.typography)) {
    lines.push(`  ${slot}: { size: ${def.size}, lh: ${def.lh}, ls: '${def.ls}', weight: ${def.weight} },`);
  }
  lines.push(`} as const;`);
  lines.push('');

  lines.push(`export type MotionDuration = keyof typeof motion.dur;`);
  lines.push(`export type MotionEase = keyof typeof motion.ease;`);
  lines.push(`export type DensityMode = keyof typeof density;`);
  lines.push(`export type Breakpoint = keyof typeof breakpoints;`);
  lines.push(`export type TypoSlot = keyof typeof typography;`);
  lines.push('');

  return lines.join('\n');
}

function writeOut(relPath, content) {
  const full = resolve(REPO, relPath);
  mkdirSync(dirname(full), { recursive: true });
  writeFileSync(full, content, 'utf8');
  console.log(`wrote ${relPath}`);
}

const cssBody = buildCss();
const tsBody = buildTs();

const tokenTargets = [
  ['frontend/src/styles/_tokens.generated.css', cssBody],
  ['frontend/src/lib/design-tokens.ts', tsBody],
  ['hone/src/renderer/src/styles/_tokens.generated.css', cssBody],
  ['hone/src/renderer/src/lib/design-tokens.ts', tsBody],
  ['cue/src/renderer/styles/_tokens.generated.css', cssBody],
  ['cue/src/renderer/lib/design-tokens.ts', tsBody],
];

for (const [path, content] of tokenTargets) {
  writeOut(path, content);
}

// Shared library files — byte-identical copies of design/src/* into each app.
// Per app lib/ + hooks/ + components/a11y/ paths.
// Drift across apps is prevented by sourcing from one canonical file.
const APP_ROOTS = {
  frontend: 'frontend/src',
  hone: 'hone/src/renderer/src',
  cue: 'cue/src/renderer',
};

const sharedFiles = [
  { src: 'focus-trap.ts', dest: 'lib/focus-trap.ts' },
  { src: 'useFocusTrap.ts', dest: 'hooks/useFocusTrap.ts' },
  { src: 'VisuallyHidden.tsx', dest: 'components/a11y/VisuallyHidden.tsx' },
  { src: 'LiveRegion.tsx', dest: 'components/a11y/LiveRegion.tsx' },
];

let sharedCount = 0;
for (const { src, dest } of sharedFiles) {
  const content = readFileSync(resolve(SHARED_SRC, src), 'utf8');
  for (const [, root] of Object.entries(APP_ROOTS)) {
    writeOut(`${root}/${dest}`, content);
    sharedCount++;
  }
}

console.log(`\ndone — ${tokenTargets.length} token files + ${sharedCount} shared lib files emitted.`);
